import React from "react";
import { useDrop } from "react-dnd";
import { recordDrop } from "./tracker";

function DropBox({ acceptName, label }) {
  const [{ isOver }, drop] = useDrop(() => ({
    accept: "ITEM",
    drop: (item) => {
      if (item.name === acceptName) {
        recordDrop(true);
        alert("Correct! ✅");
      } else {
        recordDrop(false);
        alert("Try Again ❌");
      }
    },
    collect: (monitor) => ({
      isOver: monitor.isOver(),
    }),
  }));

  return (
    <div
      ref={drop}
      style={{
        width: "120px",
        height: "120px",
        margin: "20px",
        backgroundColor: isOver ? "#90EE90" : "#ADD8E6",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        fontSize: "20px",
        borderRadius: "10px",
      }}
    >
      {label}
    </div>
  );
}

export default DropBox;
